class Solution {
public:
    int maxValue(int n, int index, int maxSum) {
        int left = index, right = n - index;
        int leftMax = index + 1, rightMax = n - index;
        int leftSum = index + 1, rightSum = n - index;
        while (leftSum + rightSum <= maxSum) {
            leftMax = std::min(leftMax + 1, (maxSum - leftSum) / (left + 1) + 1);
            rightMax = std::min(rightMax + 1, (maxSum - rightSum) / (right + 1) + 1);
            leftSum += leftMax;
            rightSum += rightMax;
            left = leftMax - 1;
            right = rightMax - 1;
        }
        return std::max(leftMax, rightMax);
    }
};
